import { INNER_ALIGN, MIDDLE_ALIGN, CENTER_ALIGN, END_ALIGN } from '../../core/align-constants';
import { TEXT_ELEMENT } from '../../core/element-constants';
import { $ZCG } from '../../core/zcglobal';
import { mathPI } from '../../core/zc-constants';
import { createElement, applyFont } from '../../utils/zcsvgutils';
import { polarToXY, d0_360, getDY } from '../polarutils';
import { translateString } from '../../utils/svg-transforms';

export function minMaxLabel(spec) {
    let { config, radius, innerRadius, data, globalFont, scale, element, format } = spec,
        { show, align, showAs, padding = 5 } = config, // align - inner,outer options are available; enable for center
        //
        labelData = show ? (showAs === 'min' ? [data[0]] : showAs === 'max' ? [data[1]] : data) : [],
        r = _radius();

    let gEle = createElement('g', '.minmaxlabelsGroup', [1], element),
        lableEle = createElement(TEXT_ELEMENT, '.minmaxlabels', labelData, gEle);

    applyFont(lableEle, [config, ...globalFont, $ZCG]);
    lableEle
        .attrs({
            'text-anchor': _textAnchor,
            dy: _dy,
            transform: _transform
        })
        .text(format);

    /*
    var edge = {
    	"left" : -w / 2,
    	"top" : -h / 2,
    	"right" : w / 2,
    	"bottom" : h / 2
    }
    callTrimText(minmaxLabel, chartObj, [0,0], 0, edge);
    */

    // Helpers
    function _textAnchor(d) {
        let a = d0_360(scale(d));

        return align === CENTER_ALIGN
            ? MIDDLE_ALIGN
            : a % mathPI == 0
            ? MIDDLE_ALIGN
            : (align === INNER_ALIGN && a < mathPI) || (align !== INNER_ALIGN && a > mathPI)
            ? END_ALIGN
            : null;
    }

    function _dy(d) {
        let a = d0_360(scale(d));

        if (align === CENTER_ALIGN) {
            return '1em';
        } else if (align === INNER_ALIGN) {
            return !(a > mathPI / 2 && a < (3 * mathPI) / 2) ? `${-getDY(a)}em` : null;
        } else {
            return a > mathPI / 2 && a < (3 * mathPI) / 2 ? `${getDY(a)}em` : null;
        }
    }

    function _transform(d) {
        let xy = polarToXY(r, scale(d)),
            pad = align === CENTER_ALIGN ? padding : 0;

        return translateString([xy[0], xy[1] + pad]);
    }

    function _radius() {
        return align === INNER_ALIGN ? innerRadius - padding : align === CENTER_ALIGN ? (radius + innerRadius) / 2 : radius + padding;
    }
}
